import { useContext, useState, useEffect, useCallback } from "react";
import {
  ConnectionState,
  type VocalBridgeError,
  type VocalBridge,
} from "@vocalbridgeai/sdk";
import { VocalBridgeContext } from "./context";

export interface UseVocalBridgeReturn {
  /** Current connection state */
  state: ConnectionState;
  /** Connect to the voice agent */
  connect: () => Promise<void>;
  /** Disconnect from the voice agent */
  disconnect: () => Promise<void>;
  /** Whether the microphone is enabled */
  isMicrophoneEnabled: boolean;
  /** Toggle microphone mute/unmute */
  toggleMicrophone: () => Promise<void>;
  /** Set microphone enabled/disabled */
  setMicrophoneEnabled: (enabled: boolean) => Promise<void>;
  /** Send a custom action to the agent */
  sendAction: (
    action: string,
    payload?: Record<string, unknown>,
  ) => Promise<void>;
  /** Agent mode string from token response */
  agentMode: string | undefined;
  /** The most recent error (if any) */
  error: VocalBridgeError | null;
  /** Access the underlying VocalBridge instance */
  client: VocalBridge;
}

/**
 * Primary hook for interacting with the voice agent.
 * Must be used within a VocalBridgeProvider.
 */
export function useVocalBridge(): UseVocalBridgeReturn {
  const context = useContext(VocalBridgeContext);
  if (!context) {
    throw new Error(
      "useVocalBridge must be used within a VocalBridgeProvider",
    );
  }

  const { client } = context;

  const [state, setState] = useState<ConnectionState>(client.state);
  const [isMicrophoneEnabled, setIsMicEnabled] = useState(
    client.isMicrophoneEnabled,
  );
  const [error, setError] = useState<VocalBridgeError | null>(null);
  const [agentMode, setAgentMode] = useState<string | undefined>(
    client.agentMode,
  );

  useEffect(() => {
    const onStateChange = (newState: ConnectionState) => {
      setState(newState);
      setAgentMode(client.agentMode);
    };
    const onMicChange = (enabled: boolean) => setIsMicEnabled(enabled);
    const onError = (err: VocalBridgeError) => setError(err);

    client.on("connectionStateChanged", onStateChange);
    client.on("microphoneChanged", onMicChange);
    client.on("error", onError);

    return () => {
      client.off("connectionStateChanged", onStateChange);
      client.off("microphoneChanged", onMicChange);
      client.off("error", onError);
    };
  }, [client]);

  const connect = useCallback(async () => {
    setError(null);
    await client.connect();
  }, [client]);

  const disconnect = useCallback(async () => {
    await client.disconnect();
  }, [client]);

  const toggleMicrophone = useCallback(async () => {
    await client.toggleMicrophone();
  }, [client]);

  const setMicrophoneEnabled = useCallback(
    async (enabled: boolean) => {
      await client.setMicrophoneEnabled(enabled);
    },
    [client],
  );

  const sendAction = useCallback(
    async (action: string, payload?: Record<string, unknown>) => {
      await client.sendAction(action, payload);
    },
    [client],
  );

  return {
    state,
    connect,
    disconnect,
    isMicrophoneEnabled,
    toggleMicrophone,
    setMicrophoneEnabled,
    sendAction,
    agentMode,
    error,
    client,
  };
}
