import { useContext, useState, useEffect, useCallback } from "react";
import type { TranscriptEntry } from "@vocalbridgeai/sdk";
import { VocalBridgeContext } from "./context";

export interface UseTranscriptReturn {
  /** Full conversation transcript */
  transcript: ReadonlyArray<TranscriptEntry>;
  /** Clear the transcript history */
  clear: () => void;
}

/**
 * Hook for accessing the live conversation transcript.
 * Automatically updates when new transcript entries arrive.
 *
 * Usage:
 * ```tsx
 * const { transcript } = useTranscript();
 * return (
 *   <div>
 *     {transcript.map((entry, i) => (
 *       <p key={i}><strong>{entry.role}:</strong> {entry.text}</p>
 *     ))}
 *   </div>
 * );
 * ```
 */
export function useTranscript(): UseTranscriptReturn {
  const context = useContext(VocalBridgeContext);
  if (!context) {
    throw new Error("useTranscript must be used within a VocalBridgeProvider");
  }

  const { client } = context;
  const [transcript, setTranscript] = useState<ReadonlyArray<TranscriptEntry>>(
    client.transcript,
  );

  useEffect(() => {
    const onTranscript = () => {
      // Create new array reference to trigger re-render
      setTranscript([...client.transcript]);
    };

    client.on("transcript", onTranscript);
    return () => {
      client.off("transcript", onTranscript);
    };
  }, [client]);

  const clear = useCallback(() => {
    client.clearTranscript();
    setTranscript([]);
  }, [client]);

  return { transcript, clear };
}
